class Solution:
    def __init__(self):
        pass
    def solve(self):
        # Use the GROUP BY clause to group the rows by region
        query = "SELECT region, COUNT(*) as count FROM sales GROUP BY region"
        # Use the ORDER BY clause to sort the results in descending order by sales amount
        query += " ORDER BY count DESC"
        return query
